    debugPrint('Slider changed: velocity = $value');
    _velocity = value;
    notifyListeners();
    _fetchFromBackend();
  }

  void setGravity(double value) {
    debugPrint('Slider changed: gravity = $value');
    _gravity = value;
    notifyListeners();
    _fetchFromBackend();
  }

