    final angleRad = _angle * 3.14159 / 180;
    return (_velocity *
            _velocity *
            (2 * _angle.abs() > 180 ? -1 : 1) *
            (2 * _angle.abs() > 180 ? 0 : 1)) /
        _gravity;
  }

  double get maxHeight {
    final angleRad = _angle * 3.14159 / 180;
    return (_velocity * _velocity * (angleRad.abs() * angleRad.abs())) /
        (2 * _gravity);
  }
}

