import 'package:flutter/material.dart';
import 'package:flutter_tts/flutter_tts.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';
import 'package:audioplayers/audioplayers.dart';

class SpeechService {
  static const String baseUrl = 'http://172.20.199.176:5000';
  final AudioPlayer _audioPlayer = AudioPlayer();
  final FlutterTts _flutterTts = FlutterTts();
  bool _useBackendTts = true;

  SpeechService() {
    _initTts();
  }

  Future<void> _initTts() async {
    await _flutterTts.setLanguage("en-US");
    await _flutterTts.setSpeechRate(0.5);
    await _flutterTts.setVolume(1.0);
    await _flutterTts.setPitch(1.0);
  }

  Future<void> speak(String text) async {
    if (_useBackendTts) {
      try {
        final response = await http
            .post(
              Uri.parse('$baseUrl/api/simulate'),
              headers: {'Content-Type': 'application/json'},
              body: jsonEncode({
                'text': text,
              }),
            )
            .timeout(const Duration(seconds: 15));

        if (response.statusCode == 200) {
          final data = jsonDecode(response.body);
          final audioUrl = data['speech_audio_url'];
          if (audioUrl != null && audioUrl.isNotEmpty) {
            await _audioPlayer.play(UrlSource(audioUrl));
            return;
          }
        }
      } catch (e) {
        debugPrint('Backend TTS failed: $e');
      }
    }

    debugPrint('Using fallback TTS');
    await _flutterTts.speak(text);
  }

  Future<void> stop() async {
    await _audioPlayer.stop();
    await _flutterTts.stop();
  }

  void dispose() {
    _audioPlayer.dispose();
    _flutterTts.stop();
  }
}

