        _controller.reset();
      }
      _controller.forward();
    }
    setState(() => _isPlaying = !_isPlaying);
  }

  @override
  Widget build(BuildContext context) {
    return Stack(
      children: [
        ListenableBuilder(
          listenable: widget.model,
          builder: (context, _) => CustomPaint(
